mapper.select:
select c.*,u.id as "author.userId",u.username as "author.username",u.bio as "author.bio",u.image as "author.image", a.author_id as articleAuthorId from comment c
join user u on u.id=c.author_id join article a on a.id=c.article_id
where c.id=#{id}

select c.*,u.id as "author.userId",u.username as "author.username",u.bio as "author.bio",u.image as "author.image", a.author_id as articleAuthorId from comment c
                                                                                                                                                            join user u on u.id=c.author_id join article a on a.id=c.article_id
where a.slug=#{slug}
